# ---- Caching Decorator ----

def redis_cache(expiry=CACHE_DEFAULT_EXPIRY, key_prefix="", bust_on=None):
    """
    Caching decorator for expensive database queries.
    
    Args:
        expiry: Cache TTL in seconds
        key_prefix: Optional prefix for cache key
        bust_on: List of HTTP methods that should bust the cache
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Generate a unique cache key based on function name and arguments
            cache_key_data = {
                "func": func.__name__,
                "args": str(args),
                "kwargs": str(sorted(kwargs.items()))
            }
            
            # Include request args if in a request context
            try:
                if request:
                    cache_key_data["request_args"] = str(sorted(request.args.items()))
                    # If the request method is in bust_on, skip cache
                    if bust_on and request.method in bust_on:
                        result = func(*args, **kwargs)
                        # Invalidate the cache
                        _invalidate_cache_for_func(func.__name__, key_prefix)
                        return result
            except RuntimeError:
                pass  # Outside request context

            key_raw = json.dumps(cache_key_data, sort_keys=True)
            key_hash = hashlib.md5(key_raw.encode()).hexdigest()
            cache_key = f"{CACHE_PREFIX}{key_prefix}{func.__name__}:{key_hash}"

            # Try to get cached result
            try:
                cached = redis_pooled_client.get(cache_key)
                if cached is not None:
                    cached_data = json.loads(cached)
                    # Add cache hit metadata
                    if isinstance(cached_data.get("result"), dict):
                        cached_data["result"]["_cache"] = "HIT"
                        cached_data["result"]["_cached_at"] = cached_data.get("cached_at")
                    return cached_data["result"]
            except (redis.RedisError, json.JSONDecodeError):
                # If Redis is down or data is corrupted, fall through to function
                pass

            # Cache miss - execute the function
            result = func(*args, **kwargs)

            # Store result in cache
            try:
                cache_data = {
                    "result": result,
                    "cached_at": datetime.utcnow().isoformat(),
                    "func": func.__name__
                }
                redis_pooled_client.set(cache_key, json.dumps(cache_data), ex=expiry)
                
                # Track cache keys for this function (for invalidation)
                func_keys_set = f"{CACHE_PREFIX}keys:{key_prefix}{func.__name__}"
                redis_pooled_client.sadd(func_keys_set, cache_key)
                redis_pooled_client.expire(func_keys_set, expiry * 2)
            except redis.RedisError:
                pass  # If Redis is down, just return the result uncached

            if isinstance(result, dict):
                result["_cache"] = "MISS"
            return result

        # Add cache invalidation method to the wrapper
        wrapper.invalidate_cache = lambda: _invalidate_cache_for_func(
            func.__name__, key_prefix
        )
        return wrapper
    return decorator


def _invalidate_cache_for_func(func_name, key_prefix=""):
    """Invalidate all cache entries for a specific function."""
    try:
        func_keys_set = f"{CACHE_PREFIX}keys:{key_prefix}{func_name}"
        keys = redis_pooled_client.smembers(func_keys_set)
        if keys:
            redis_pooled_client.delete(*keys)
        redis_pooled_client.delete(func_keys_set)
    except redis.RedisError:
        pass


def invalidate_cache_pattern(pattern):
    """Invalidate all cache entries matching a pattern."""
    try:
        cursor = 0
        while True:
            cursor, keys = redis_pooled_client.scan(
                cursor=cursor, match=f"{CACHE_PREFIX}{pattern}*", count=100
            )
            if keys:
                redis_pooled_client.delete(*keys)
            if cursor == 0:
                break
    except redis.RedisError:
        pass


