@app.route('/api/cache/invalidate', methods=['POST'])
def invalidate_cache():
    """Invalidate cache entries."""
    data = request.get_json() or {}
    pattern = data.get('pattern', '')

    if pattern:
        invalidate_cache_pattern(pattern)
        return jsonify({"message": f"Cache invalidated for pattern: {pattern}"})

    # Invalidate specific function caches
    func_name = data.get('function')
    if func_name == 'users':
        get_all_users.invalidate_cache()
    elif func_name == 'stats':
        get_dashboard_stats.invalidate_cache()
    elif func_name == 'products':
        search_products.invalidate_cache()
    elif func_name == 'all':
        get_all_users.invalidate_cache()
        get_dashboard_stats.invalidate_cache()
        search_products.invalidate_cache()
        invalidate_cache_pattern("")
    else:
        return jsonify({"error": "Specify 'pattern' or 'function' to invalidate"}), 400

    return jsonify({"message": f"Cache invalidated for function: {func_name}"})


@app.route('/api/cache/stats', methods=['GET'])
def cache_stats():
    """Get Redis cache statistics."""
    try:
        info = redis_pooled_client.info()
        dbsize = redis_pooled_client.dbsize()

        # Count session and cache keys
        session_count = 0
        cache_count = 0
        cursor = 0
        while True:
            cursor, keys = redis_pooled_client.scan(cursor=cursor, count=100)
            for key in keys:
                if key.startswith(SESSION_PREFIX):
                    session_count += 1
                elif key.startswith(CACHE_PREFIX):
                    cache_count += 1
            if cursor == 0:
                break

        return jsonify({
            "redis_version": info.get("redis_version"),
            "connected_clients": info.get("connected_clients"),
            "used_memory_human": info.get("used_memory_human"),
            "total_keys": dbsize,
            "session_keys": session_count,
            "cache_keys": cache_count,
            "keyspace_hits": info.get("keyspace_hits", 0),
            "keyspace_misses": info.get("keyspace_misses", 0),
            "hit_rate": round(
                info.get("keyspace_hits", 0) /
                max(info.get("keyspace_hits", 0) + info.get("keyspace_misses", 0), 1) * 100, 2
            ),
            "uptime_seconds": info.get("uptime_in_seconds"),
        })
    except redis.RedisError as e:
        return jsonify({"error": f"Redis connection error: {str(e)}"}), 503


