# ---- Rate Limiting with Redis ----

def rate_limit(max_requests=100, window_seconds=60):
    """Rate limiting decorator using Redis sliding window."""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            try:
                client_ip = request.remote_addr
                key = f"rate_limit:{func.__name__}:{client_ip}"
                
                current = redis_pooled_client.get(key)
                if current is not None and int(current) >= max_requests:
                    ttl = redis_pooled_client.ttl(key)
                    return jsonify({
                        "error": "Rate limit exceeded",
                        "retry_after": ttl,
                        "max_requests": max_requests,
                        "window_seconds": window_seconds
                    }), 429
                
                pipe = redis_pooled_client.pipeline()
                pipe.incr(key)
                pipe.expire(key, window_seconds)
                pipe.execute()
            except redis.RedisError:
                pass  # If Redis is down, allow the request through
            
            return func(*args, **kwargs)
        return wrapper
    return decorator


